import { useState, useEffect } from "react";
import api from "../services/api";
import PostCard from "../components/kid/PostCard";
import StoriesBar from "../components/kid/StoriesBar";
import "./Feed.css";

export default function Feed() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [newPost, setNewPost] = useState("");
  const [posting, setPosting] = useState(false);

  // Get current user from localStorage
  const user = (() => {
    try { return JSON.parse(localStorage.getItem("user") || "{}"); }
    catch { return {}; }
  })();

  const loadFeed = async () => {
    try {
      setError(null);
      const res = await api.get("/posts/feed");
      // Handle both { data: [] } and { success, data: [] } shapes
      const feedData = res.data?.data ?? res.data ?? [];
      setPosts(Array.isArray(feedData) ? feedData : []);
    } catch (err) {
      console.error("Feed load error:", err);
      setError(err.response?.data?.message || "Could not load feed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadFeed(); }, []);

  const handlePost = async () => {
    if (!newPost.trim()) return;
    setPosting(true);
    try {
      const res = await api.post("/posts", { content: newPost });
      const created = res.data?.data ?? res.data;
      if (created) setPosts(prev => [created, ...prev]);
      setNewPost("");
    } catch (err) {
      alert(err.response?.data?.message || "Could not create post.");
    } finally {
      setPosting(false);
    }
  };

  const handleDeleted = (id) => {
    setPosts(prev => prev.filter(p => p.id !== id));
  };

  return (
    <div className="feed-container">
      <StoriesBar />

      {/* Compose box */}
      <div className="compose-box">
        <img
          src={user.avatar_url || `https://api.dicebear.com/7.x/bottts/svg?seed=${user.username || "me"}`}
          alt="you"
          className="compose-avatar"
        />
        <div className="compose-input-wrap">
          <textarea
            value={newPost}
            onChange={e => setNewPost(e.target.value)}
            placeholder="Share something kind today! 🌟"
            rows={2}
            maxLength={1000}
          />
          <button onClick={handlePost} disabled={posting || !newPost.trim()}>
            {posting ? "Posting..." : "Post 🚀"}
          </button>
        </div>
      </div>

      {/* Feed content */}
      {loading && (
        <div className="feed-loading">
          <div className="spinner" />
          <p>Loading your feed...</p>
        </div>
      )}

      {error && !loading && (
        <div className="feed-error">
          <p>😕 {error}</p>
          <button onClick={loadFeed}>Try again</button>
        </div>
      )}

      {!loading && !error && posts.length === 0 && (
        <div className="feed-empty">
          <p>🌈 Nothing here yet!</p>
          <p>Add some friends or be the first to post something kind.</p>
        </div>
      )}

      {!loading && posts.map(post => (
        <PostCard
          key={post.id}
          post={post}
          currentUserId={user.id}
          onDeleted={handleDeleted}
        />
      ))}
    </div>
  );
}
